Hieronder een Next.js (App Router) server action met Prisma. Klanten melden dat het winkelwagentotaal te laag is zodra ze meer dan 1 stuk van een product bestellen. Analyseer de code, vind de werkelijke oorzaak, leg uit waarom het fout gaat, benoem randgevallen, en lever de gefixte productie-code.

```ts
// app/actions/cart.ts
'use server'
import { prisma } from '@/lib/prisma'

export async function getCartTotal(cartId: string) {
  const items = await prisma.cartItem.findMany({
    where: { cartId },
    include: { product: true },
  })

  let totalCents = 0
  for (const item of items) {
    totalCents += item.product.priceCents
  }

  return { totalCents, currency: 'EUR' }
}
```

Schema (relevant deel):
```prisma
model CartItem {
  id        String  @id @default(cuid())
  cartId    String
  quantity  Int
  product   Product @relation(fields: [productId], references: [id])
  productId String
}
model Product { id String @id; priceCents Int }
```
